  "sourcesContent": [":host {\n  --ink: #f7f3eb;\n  --ink-soft: #cfbca2;\n  --line: #4f3f2f;\n  --panel-bg: rgba(33, 25, 18, 0.78);\n  --accent: #f8b84e;\n  --accent-strong: #ff8f3c;\n  --field-bg: rgba(12, 9, 7, 0.74);\n  display: block;\n  height: 100%;\n  min-height: 100dvh;\n}\n\n.auth-scene {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  min-height: 100dvh;\n  overflow: hidden;\n  color: var(--ink);\n  font-family: 'Space Grotesk', 'Segoe UI', sans-serif;\n  background:\n    radial-gradient(circle at 18% 12%, rgba(255, 177, 89, 0.18), transparent 38%),\n    radial-gradient(circle at 78% 84%, rgba(255, 120, 57, 0.16), transparent 34%),\n    linear-gradient(160deg, #120f0a 0%, #1d120f 44%, #2c1911 100%);\n}\n\n.noise-layer {\n  position: absolute;\n  inset: 0;\n  pointer-events: none;\n  opacity: 0.2;\n  background-image:\n    linear-gradient(transparent 95%, rgba(255, 255, 255, 0.07) 95%),\n    linear-gradient(90deg, transparent 95%, rgba(255, 255, 255, 0.05) 95%);\n  background-size: 22px 22px;\n  animation: drift 18s linear infinite;\n}\n\n.scene-layout {\n  position: relative;\n  z-index: 1;\n  flex: 1;\n  width: min(1100px, 100% - 2rem);\n  margin: 0 auto;\n  min-height: 100dvh;\n  padding-top: 1.2rem;\n  padding-bottom: 1rem;\n  display: grid;\n  align-items: center;\n  gap: 2rem;\n  grid-template-columns: minmax(0, 1.05fr) minmax(420px, 1fr);\n}\n\n.mood-panel {\n  padding: 2rem 1rem;\n  animation: rise-in 0.85s ease-out both;\n}\n\n.kicker {\n  margin: 0;\n  text-transform: uppercase;\n  letter-spacing: 0.28em;\n  font-size: 0.76rem;\n  color: var(--ink-soft);\n}\n\n.mood-panel h1 {\n  margin: 0.7rem 0 0;\n  font-size: clamp(2.1rem, 6vw, 4.7rem);\n  line-height: 0.95;\n  letter-spacing: -0.03em;\n  text-wrap: balance;\n}\n\n.mood-panel h1 span {\n  display: block;\n  color: var(--accent);\n}\n\n.lede {\n  margin: 1.35rem 0 0;\n  max-width: 34ch;\n  line-height: 1.55;\n  color: #f0e2cd;\n}\n\n.ticker {\n  margin-top: 1.9rem;\n  border-top: 1px solid rgba(255, 245, 224, 0.24);\n  border-bottom: 1px solid rgba(255, 245, 224, 0.24);\n  position: relative;\n  display: flex;\n  align-items: center;\n  overflow: hidden;\n  height: 2.2rem;\n  padding: 0.65rem 0;\n}\n\n.ticker-rail {\n  position: relative;\n  width: 100%;\n  height: 1rem;\n}\n\n.ticker-track {\n  position: absolute;\n  left: 0;\n  top: 50%;\n  display: flex;\n  align-items: center;\n  flex: 0 0 auto;\n  gap: 1rem;\n  width: max-content;\n  will-change: transform;\n  animation: ticker-loop 14s linear infinite;\n  transform: translate3d(100%, -50%, 0);\n}\n\n.ticker-track:last-child {\n  animation-delay: -7s;\n}\n\n.ticker span {\n  flex: 0 0 auto;\n  text-transform: uppercase;\n  font-size: 0.8rem;\n  letter-spacing: 0.18em;\n  white-space: nowrap;\n  color: #ffd18b;\n}\n\n.login-panel {\n  border: 1px solid rgba(255, 225, 178, 0.22);\n  background: var(--panel-bg);\n  backdrop-filter: blur(8px);\n  border-radius: 1.4rem;\n  width: 100%;\n  max-width: 540px;\n  justify-self: end;\n  padding: 2rem 2.15rem;\n  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.42);\n  animation: rise-in 0.75s ease-out 0.15s both;\n}\n\n.login-panel.is-transitioning .panel-copy,\n.login-panel.is-transitioning .panel-body {\n  animation: soft-switch 0.22s ease-out;\n}\n\n.panel-head {\n  margin-bottom: 1.25rem;\n}\n\n.mode-switch {\n  display: inline-flex;\n  width: 100%;\n  gap: 0.55rem;\n  padding: 0.35rem;\n  border-radius: 999px;\n  border: 1px solid rgba(255, 225, 178, 0.18);\n  background: rgba(14, 10, 7, 0.52);\n}\n\n.mode-chip {\n  flex: 1;\n  border: 0;\n  border-radius: 999px;\n  padding: 0.72rem 0.95rem;\n  background: transparent;\n  color: var(--ink-soft);\n  font-size: 0.8rem;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n  text-align: center;\n  white-space: nowrap;\n  cursor: pointer;\n  transition: background 0.2s ease, color 0.2s ease, transform 0.2s ease;\n}\n\n.mode-chip.active {\n  color: #1b110a;\n  background: linear-gradient(90deg, #ffcc7a, #ff9d52);\n}\n\n.panel-copy {\n  position: relative;\n  display: flex;\n  width: 100%;\n  align-items: start;\n  justify-content: flex-end;\n  overflow: hidden;\n  margin-top: 1rem;\n}\n\n.panel-page {\n  flex: 0 0 100%;\n  min-width: 0;\n  text-align: right;\n}\n\n.panel-copy.swap-left {\n  transform: none;\n}\n\n.panel-note {\n  margin: 0.35rem 0 0;\n  color: var(--ink-soft);\n  line-height: 1.45;\n  font-size: 0.92rem;\n}\n\n.panel-body {\n  overflow: hidden;\n  margin-top: 0.8rem;\n}\n\n.auth-form {\n  animation: form-slide-in 0.24s ease-out;\n}\n\n.eyebrow {\n  margin: 0;\n  color: var(--ink-soft);\n  text-transform: uppercase;\n  letter-spacing: 0.2em;\n  font-size: 0.72rem;\n}\n\n.panel-head h2 {\n  margin: 0.35rem 0 0;\n  font-size: clamp(1.8rem, 3vw, 2.2rem);\n  letter-spacing: -0.02em;\n}\n\n.login-form {\n  display: grid;\n  gap: 0.45rem;\n}\n\n.login-form label {\n  color: #f4dcc2;\n  font-size: 0.88rem;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n  margin-bottom: 0.15rem;\n}\n\n.login-form input {\n  width: 100%;\n  border-radius: 0.85rem;\n  border: 1px solid var(--line);\n  background: var(--field-bg);\n  color: var(--ink);\n  font-size: 1rem;\n  padding: 0.8rem 0.9rem;\n  transition: border-color 0.25s ease, transform 0.2s ease;\n}\n\n.login-form input:focus {\n  outline: none;\n  border-color: var(--accent);\n  transform: translateY(-1px);\n}\n\n.password-wrap {\n  position: relative;\n}\n\n.password-wrap input {\n  padding-right: 5.5rem;\n}\n\n.toggle-visibility {\n  position: absolute;\n  top: 50%;\n  right: 0.5rem;\n  transform: translateY(-50%);\n  border: 0;\n  border-radius: 0.55rem;\n  min-height: 2rem;\n  padding: 0.4rem 0.65rem;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  font-size: 0.67rem;\n  color: #1b110a;\n  background: linear-gradient(90deg, #ffcc7a, #ff9d52);\n  touch-action: manipulation;\n  cursor: pointer;\n}\n\n.submit-btn {\n  margin-top: 0.6rem;\n  border: none;\n  border-radius: 0.95rem;\n  min-height: 3.1rem;\n  padding: 0.95rem 1.05rem;\n  font-weight: 700;\n  letter-spacing: 0.03em;\n  color: #1c130f;\n  background: linear-gradient(95deg, var(--accent), var(--accent-strong));\n  touch-action: manipulation;\n  cursor: pointer;\n  transition: transform 0.2s ease, filter 0.2s ease;\n}\n\n.submit-btn:hover {\n  transform: translateY(-2px);\n  filter: brightness(1.05);\n}\n\n.status {\n  margin-top: 0.1rem;\n  padding: 0.55rem 0.7rem;\n  border-radius: 0.7rem;\n  border: 1px solid #8c3c33;\n  background: rgba(97, 33, 27, 0.55);\n  color: #ffd9d2;\n  font-size: 0.92rem;\n}\n\n.status.success {\n  border-color: rgba(113, 182, 118, 0.35);\n  background: rgba(22, 74, 38, 0.55);\n  color: #d4f7d8;\n}\n\n.form-hint {\n  margin: 0.35rem 0 0;\n  color: var(--ink-soft);\n  font-size: 0.88rem;\n}\n\n.text-link {\n  border: 0;\n  padding: 0;\n  margin-left: 0.3rem;\n  background: none;\n  color: var(--accent);\n  font: inherit;\n  cursor: pointer;\n}\n\n.text-link:hover {\n  color: var(--accent-strong);\n}\n\n@keyframes rise-in {\n  from {\n    opacity: 0;\n    transform: translateY(18px) scale(0.99);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0) scale(1);\n  }\n}\n\n@keyframes ticker-loop {\n  from {\n    transform: translate3d(100%, -50%, 0);\n  }\n  to {\n    transform: translate3d(-100%, -50%, 0);\n  }\n}\n\n@keyframes drift {\n  from {\n    transform: translate(0, 0);\n  }\n  to {\n    transform: translate(-22px, -22px);\n  }\n}\n\n@keyframes soft-switch {\n  from {\n    opacity: 0.72;\n    transform: translateY(4px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes form-slide-in {\n  from {\n    opacity: 0;\n    transform: translateX(10px);\n  }\n  to {\n    opacity: 1;\n    transform: translateX(0);\n  }\n}\n\n@media (max-width: 940px) {\n  .scene-layout {\n    grid-template-columns: 1fr;\n    min-height: auto;\n    padding-top: 1.1rem;\n    padding: 1.25rem 0;\n  }\n\n  .login-panel {\n    max-width: 95%;\n    justify-self: stretch;\n  }\n\n  .mood-panel {\n    padding: 1rem 0.3rem 0;\n  }\n\n  .lede {\n    max-width: 46ch;\n  }\n}\n\n@media (max-width: 560px) {\n  .auth-scene {\n    min-height: 100dvh;\n    padding: max(0.9rem, env(safe-area-inset-top)) 0 max(1rem, env(safe-area-inset-bottom));\n  }\n\n  .scene-layout {\n    width: min(100% - 1rem, 520px);\n    min-height: calc(100dvh - max(0.75rem, env(safe-area-inset-top)) - max(1rem, env(safe-area-inset-bottom)));\n    gap: 0.95rem;\n    padding-top: 0.8rem;\n  }\n\n  .mood-panel {\n    padding: 0.25rem 0.2rem 0;\n  }\n\n  .kicker {\n    font-size: 0.68rem;\n    letter-spacing: 0.22em;\n  }\n\n  .mood-panel h1 {\n    font-size: clamp(1.8rem, 10vw, 2.8rem);\n  }\n\n  .lede {\n    margin-top: 0.95rem;\n    font-size: 0.94rem;\n    line-height: 1.48;\n  }\n\n  .login-panel {\n    padding: 1rem;\n    border-radius: 1rem;\n    backdrop-filter: blur(5px);\n    box-shadow: 0 16px 45px rgba(0, 0, 0, 0.38);\n  }\n\n  .mode-switch {\n    width: 100%;\n    justify-content: space-between;\n  }\n\n  .mode-chip {\n    flex: 1;\n    padding: 0.66rem 0.8rem;\n    font-size: 0.72rem;\n  }\n\n  .panel-copy {\n    margin-top: 0.85rem;\n  }\n\n  .ticker {\n    margin-top: 0.8rem;\n    padding: 0.48rem 0;\n  }\n\n  .ticker span {\n    font-size: 0.7rem;\n    letter-spacing: 0.16em;\n    \n  }\n\n  .login-form {\n    gap: 0.62rem;\n  }\n\n  .login-form label {\n    font-size: 0.78rem;\n  }\n\n  .login-form input {\n    padding: 0.86rem 0.82rem;\n    border-radius: 0.75rem;\n  }\n\n  .password-wrap input {\n    padding-right: 5.75rem;\n  }\n\n  .toggle-visibility {\n    right: 0.38rem;\n    font-size: 0.62rem;\n    min-height: 1.9rem;\n  }\n\n  .submit-btn {\n    margin-top: 0.5rem;\n    min-height: 3.1rem;\n    font-size: 0.95rem;\n  }\n}\n\n@media (max-width: 420px) {\n  .scene-layout {\n    width: calc(100% - 0.7rem);\n  }\n\n  .mood-panel h1 {\n    font-size: clamp(1.58rem, 9.2vw, 2.2rem);\n  }\n\n  .lede {\n    display: none;\n  }\n\n  .ticker {\n    margin-top: 0.65rem;\n  }\n\n  .panel-head h2 {\n    font-size: 1.55rem;\n  }\n\n  .login-panel {\n    padding: 0.9rem;\n    border-radius: 0.9rem;\n  }\n\n  .status {\n    font-size: 0.86rem;\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .noise-layer,\n  .ticker-track,\n  .mood-panel,\n  .login-panel,\n  .auth-form,\n  .login-panel.is-transitioning .panel-copy,\n  .login-panel.is-transitioning .panel-body {\n    animation: none;\n  }\n}\n"],
