  "sourcesContent": [":host {\r\n  --ink: #f7f3eb;\r\n  --ink-soft: #cfbca2;\r\n  --line: #4f3f2f;\r\n  --panel-bg: rgba(33, 25, 18, 0.78);\r\n  --accent: #f8b84e;\r\n  --accent-strong: #ff8f3c;\r\n  --field-bg: rgba(12, 9, 7, 0.74);\r\n  display: block;\r\n  height: 100%;\r\n  min-height: 100dvh;\r\n}\r\n\r\n.auth-scene {\r\n  position: relative;\r\n  display: flex;\r\n  flex-direction: column;\r\n  min-height: 100dvh;\r\n  overflow: hidden;\r\n  color: var(--ink);\r\n  font-family: 'Space Grotesk', 'Segoe UI', sans-serif;\r\n  background:\r\n    radial-gradient(circle at 18% 12%, rgba(255, 177, 89, 0.18), transparent 38%),\r\n    radial-gradient(circle at 78% 84%, rgba(255, 120, 57, 0.16), transparent 34%),\r\n    linear-gradient(160deg, #120f0a 0%, #1d120f 44%, #2c1911 100%);\r\n}\r\n\r\n.noise-layer {\r\n  position: absolute;\r\n  inset: 0;\r\n  pointer-events: none;\r\n  opacity: 0.2;\r\n  background-image:\r\n    linear-gradient(transparent 95%, rgba(255, 255, 255, 0.07) 95%),\r\n    linear-gradient(90deg, transparent 95%, rgba(255, 255, 255, 0.05) 95%);\r\n  background-size: 22px 22px;\r\n  animation: drift 18s linear infinite;\r\n}\r\n\r\n.scene-layout {\r\n  position: relative;\r\n  z-index: 1;\r\n  flex: 1;\r\n  width: min(1100px, 100% - 2rem);\r\n  margin: 0 auto;\r\n  min-height: 100dvh;\r\n  display: grid;\r\n  align-items: center;\r\n  gap: 2rem;\r\n  grid-template-columns: minmax(0, 1.05fr) minmax(420px, 1fr);\r\n}\r\n\r\n.mood-panel {\r\n  padding: 2rem 1rem;\r\n  animation: rise-in 0.85s ease-out both;\r\n}\r\n\r\n.kicker {\r\n  margin: 0;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.28em;\r\n  font-size: 0.76rem;\r\n  color: var(--ink-soft);\r\n}\r\n\r\n.mood-panel h1 {\r\n  margin: 0.7rem 0 0;\r\n  font-size: clamp(2.1rem, 6vw, 4.7rem);\r\n  line-height: 0.95;\r\n  letter-spacing: -0.03em;\r\n  text-wrap: balance;\r\n}\r\n\r\n.mood-panel h1 span {\r\n  display: block;\r\n  color: var(--accent);\r\n}\r\n\r\n.lede {\r\n  margin: 1.35rem 0 0;\r\n  max-width: 34ch;\r\n  line-height: 1.55;\r\n  color: #f0e2cd;\r\n}\r\n\r\n.ticker {\r\n  margin-top: 1.9rem;\r\n  border-top: 1px solid rgba(255, 245, 224, 0.24);\r\n  border-bottom: 1px solid rgba(255, 245, 224, 0.24);\r\n  position: relative;\r\n  display: flex;\r\n  align-items: center;\r\n  overflow: hidden;\r\n  height: 2.2rem;\r\n  padding: 0.65rem 0;\r\n}\r\n\r\n.ticker-rail {\r\n  position: relative;\r\n  width: 100%;\r\n  height: 1rem;\r\n}\r\n\r\n.ticker-track {\r\n  position: absolute;\r\n  left: 0;\r\n  top: 50%;\r\n  display: flex;\r\n  align-items: center;\r\n  flex: 0 0 auto;\r\n  gap: 1rem;\r\n  width: max-content;\r\n  will-change: transform;\r\n  animation: ticker-loop 14s linear infinite;\r\n  transform: translate3d(100%, -50%, 0);\r\n}\r\n\r\n.ticker-track:last-child {\r\n  animation-delay: -7s;\r\n}\r\n\r\n.ticker span {\r\n  flex: 0 0 auto;\r\n  text-transform: uppercase;\r\n  font-size: 0.8rem;\r\n  letter-spacing: 0.18em;\r\n  white-space: nowrap;\r\n  color: #ffd18b;\r\n}\r\n\r\n.login-panel {\r\n  border: 1px solid rgba(255, 225, 178, 0.22);\r\n  background: var(--panel-bg);\r\n  backdrop-filter: blur(8px);\r\n  border-radius: 1.4rem;\r\n  width: 100%;\r\n  max-width: 540px;\r\n  justify-self: end;\r\n  padding: 2rem 2.15rem;\r\n  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.42);\r\n  animation: rise-in 0.75s ease-out 0.15s both;\r\n}\r\n\r\n.login-panel.is-transitioning .panel-copy,\r\n.login-panel.is-transitioning .panel-body {\r\n  animation: soft-switch 0.22s ease-out;\r\n}\r\n\r\n.panel-head {\r\n  margin-bottom: 1.25rem;\r\n}\r\n\r\n.mode-switch {\r\n  display: inline-flex;\r\n  gap: 0.45rem;\r\n  padding: 0.35rem;\r\n  border-radius: 999px;\r\n  border: 1px solid rgba(255, 225, 178, 0.18);\r\n  background: rgba(14, 10, 7, 0.52);\r\n}\r\n\r\n.mode-chip {\r\n  border: 0;\r\n  border-radius: 999px;\r\n  padding: 0.72rem 0.95rem;\r\n  background: transparent;\r\n  color: var(--ink-soft);\r\n  font-size: 0.8rem;\r\n  letter-spacing: 0.08em;\r\n  text-transform: uppercase;\r\n  cursor: pointer;\r\n  transition: background 0.2s ease, color 0.2s ease, transform 0.2s ease;\r\n}\r\n\r\n.mode-chip.active {\r\n  color: #1b110a;\r\n  background: linear-gradient(90deg, #ffcc7a, #ff9d52);\r\n}\r\n\r\n.panel-copy {\r\n  position: relative;\r\n  display: flex;\r\n  width: 200%;\r\n  align-items: start;\r\n  overflow: hidden;\r\n  margin-top: 1rem;\r\n  transition: transform 0.24s ease;\r\n}\r\n\r\n.panel-page {\r\n  flex: 0 0 50%;\r\n  min-width: 0;\r\n}\r\n\r\n.panel-copy.swap-left {\r\n  transform: translateX(-50%);\r\n}\r\n\r\n.panel-note {\r\n  margin: 0.35rem 0 0;\r\n  color: var(--ink-soft);\r\n  line-height: 1.45;\r\n  font-size: 0.92rem;\r\n}\r\n\r\n.panel-body {\r\n  overflow: hidden;\r\n  margin-top: 0.8rem;\r\n}\r\n\r\n.auth-form {\r\n  animation: form-slide-in 0.24s ease-out;\r\n}\r\n\r\n.eyebrow {\r\n  margin: 0;\r\n  color: var(--ink-soft);\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.2em;\r\n  font-size: 0.72rem;\r\n}\r\n\r\n.panel-head h2 {\r\n  margin: 0.35rem 0 0;\r\n  font-size: clamp(1.8rem, 3vw, 2.2rem);\r\n  letter-spacing: -0.02em;\r\n}\r\n\r\n.login-form {\r\n  display: grid;\r\n  gap: 0.9rem;\r\n}\r\n\r\n.login-form label {\r\n  color: #f4dcc2;\r\n  font-size: 0.88rem;\r\n  letter-spacing: 0.05em;\r\n  text-transform: uppercase;\r\n}\r\n\r\n.login-form input {\r\n  width: 100%;\r\n  border-radius: 0.85rem;\r\n  border: 1px solid var(--line);\r\n  background: var(--field-bg);\r\n  color: var(--ink);\r\n  font-size: 1rem;\r\n  padding: 0.95rem 0.9rem;\r\n  transition: border-color 0.25s ease, transform 0.2s ease;\r\n}\r\n\r\n.login-form input:focus {\r\n  outline: none;\r\n  border-color: var(--accent);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.password-wrap {\r\n  position: relative;\r\n}\r\n\r\n.password-wrap input {\r\n  padding-right: 5.5rem;\r\n}\r\n\r\n.toggle-visibility {\r\n  position: absolute;\r\n  top: 50%;\r\n  right: 0.5rem;\r\n  transform: translateY(-50%);\r\n  border: 0;\r\n  border-radius: 0.55rem;\r\n  min-height: 2rem;\r\n  padding: 0.4rem 0.65rem;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.08em;\r\n  font-size: 0.67rem;\r\n  color: #1b110a;\r\n  background: linear-gradient(90deg, #ffcc7a, #ff9d52);\r\n  touch-action: manipulation;\r\n  cursor: pointer;\r\n}\r\n\r\n.submit-btn {\r\n  margin-top: 0.8rem;\r\n  border: none;\r\n  border-radius: 0.95rem;\r\n  min-height: 3.25rem;\r\n  padding: 1rem 1.05rem;\r\n  font-weight: 700;\r\n  letter-spacing: 0.03em;\r\n  color: #1c130f;\r\n  background: linear-gradient(95deg, var(--accent), var(--accent-strong));\r\n  touch-action: manipulation;\r\n  cursor: pointer;\r\n  transition: transform 0.2s ease, filter 0.2s ease;\r\n}\r\n\r\n.submit-btn:hover {\r\n  transform: translateY(-2px);\r\n  filter: brightness(1.05);\r\n}\r\n\r\n.status {\r\n  padding: 0.64rem 0.75rem;\r\n  border-radius: 0.7rem;\r\n  border: 1px solid #8c3c33;\r\n  background: rgba(97, 33, 27, 0.55);\r\n  color: #ffd9d2;\r\n  font-size: 0.92rem;\r\n}\r\n\r\n.status.success {\r\n  border-color: rgba(113, 182, 118, 0.35);\r\n  background: rgba(22, 74, 38, 0.55);\r\n  color: #d4f7d8;\r\n}\r\n\r\n.form-hint {\r\n  margin: 0.35rem 0 0;\r\n  color: var(--ink-soft);\r\n  font-size: 0.88rem;\r\n}\r\n\r\n.text-link {\r\n  border: 0;\r\n  padding: 0;\r\n  margin-left: 0.3rem;\r\n  background: none;\r\n  color: var(--accent);\r\n  font: inherit;\r\n  cursor: pointer;\r\n}\r\n\r\n.text-link:hover {\r\n  color: var(--accent-strong);\r\n}\r\n\r\n@keyframes rise-in {\r\n  from {\r\n    opacity: 0;\r\n    transform: translateY(18px) scale(0.99);\r\n  }\r\n  to {\r\n    opacity: 1;\r\n    transform: translateY(0) scale(1);\r\n  }\r\n}\r\n\r\n@keyframes ticker-loop {\r\n  from {\r\n    transform: translate3d(100%, -50%, 0);\r\n  }\r\n  to {\r\n    transform: translate3d(-100%, -50%, 0);\r\n  }\r\n}\r\n\r\n@keyframes drift {\r\n  from {\r\n    transform: translate(0, 0);\r\n  }\r\n  to {\r\n    transform: translate(-22px, -22px);\r\n  }\r\n}\r\n\r\n@keyframes soft-switch {\r\n  from {\r\n    opacity: 0.72;\r\n    transform: translateY(4px);\r\n  }\r\n  to {\r\n    opacity: 1;\r\n    transform: translateY(0);\r\n  }\r\n}\r\n\r\n@keyframes form-slide-in {\r\n  from {\r\n    opacity: 0;\r\n    transform: translateX(10px);\r\n  }\r\n  to {\r\n    opacity: 1;\r\n    transform: translateX(0);\r\n  }\r\n}\r\n\r\n@media (max-width: 940px) {\r\n  .scene-layout {\r\n    grid-template-columns: 1fr;\r\n    padding: 1.25rem 0;\r\n  }\r\n\r\n  .login-panel {\r\n    max-width: 95%;\r\n    justify-self: stretch;\r\n  }\r\n\r\n  .mood-panel {\r\n    padding: 1rem 0.3rem 0;\r\n  }\r\n\r\n  .lede {\r\n    max-width: 46ch;\r\n  }\r\n}\r\n\r\n@media (max-width: 560px) {\r\n  .auth-scene {\r\n    min-height: 100dvh;\r\n    padding: max(0.75rem, env(safe-area-inset-top)) 0 max(1rem, env(safe-area-inset-bottom));\r\n  }\r\n\r\n  .scene-layout {\r\n    width: min(100% - 1rem, 520px);\r\n    min-height: calc(100dvh - max(0.75rem, env(safe-area-inset-top)) - max(1rem, env(safe-area-inset-bottom)));\r\n    gap: 0.95rem;\r\n  }\r\n\r\n  .mood-panel {\r\n    padding: 0.25rem 0.2rem 0;\r\n  }\r\n\r\n  .kicker {\r\n    font-size: 0.68rem;\r\n    letter-spacing: 0.22em;\r\n  }\r\n\r\n  .mood-panel h1 {\r\n    font-size: clamp(1.8rem, 10vw, 2.8rem);\r\n  }\r\n\r\n  .lede {\r\n    margin-top: 0.95rem;\r\n    font-size: 0.94rem;\r\n    line-height: 1.48;\r\n  }\r\n\r\n  .login-panel {\r\n    padding: 1rem;\r\n    border-radius: 1rem;\r\n    backdrop-filter: blur(5px);\r\n    box-shadow: 0 16px 45px rgba(0, 0, 0, 0.38);\r\n  }\r\n\r\n  .mode-switch {\r\n    width: 100%;\r\n    justify-content: space-between;\r\n  }\r\n\r\n  .mode-chip {\r\n    flex: 1;\r\n    padding: 0.66rem 0.8rem;\r\n    font-size: 0.72rem;\r\n  }\r\n\r\n  .panel-copy {\r\n    margin-top: 0.85rem;\r\n  }\r\n\r\n  .ticker {\r\n    margin-top: 0.8rem;\r\n    padding: 0.48rem 0;\r\n  }\r\n\r\n  .ticker span {\r\n    font-size: 0.7rem;\r\n    letter-spacing: 0.16em;\r\n    \r\n  }\r\n\r\n  .login-form {\r\n    gap: 0.62rem;\r\n  }\r\n\r\n  .login-form label {\r\n    font-size: 0.78rem;\r\n  }\r\n\r\n  .login-form input {\r\n    padding: 0.86rem 0.82rem;\r\n    border-radius: 0.75rem;\r\n  }\r\n\r\n  .password-wrap input {\r\n    padding-right: 5.75rem;\r\n  }\r\n\r\n  .toggle-visibility {\r\n    right: 0.38rem;\r\n    font-size: 0.62rem;\r\n    min-height: 1.9rem;\r\n  }\r\n\r\n  .submit-btn {\r\n    margin-top: 0.5rem;\r\n    min-height: 3.1rem;\r\n    font-size: 0.95rem;\r\n  }\r\n}\r\n\r\n@media (max-width: 420px) {\r\n  .scene-layout {\r\n    width: calc(100% - 0.7rem);\r\n  }\r\n\r\n  .mood-panel h1 {\r\n    font-size: clamp(1.58rem, 9.2vw, 2.2rem);\r\n  }\r\n\r\n  .lede {\r\n    display: none;\r\n  }\r\n\r\n  .ticker {\r\n    margin-top: 0.65rem;\r\n  }\r\n\r\n  .panel-head h2 {\r\n    font-size: 1.55rem;\r\n  }\r\n\r\n  .login-panel {\r\n    padding: 0.9rem;\r\n    border-radius: 0.9rem;\r\n  }\r\n\r\n  .status {\r\n    font-size: 0.86rem;\r\n  }\r\n}\r\n\r\n@media (prefers-reduced-motion: reduce) {\r\n  .noise-layer,\r\n  .ticker-track,\r\n  .mood-panel,\r\n  .login-panel,\r\n  .auth-form,\r\n  .login-panel.is-transitioning .panel-copy,\r\n  .login-panel.is-transitioning .panel-body {\r\n    animation: none;\r\n  }\r\n}\r\n"],
